function ProductCard({ name, price, discountedPrice, quantity }) {
  const isPromotion = discountedPrice && discountedPrice < price;
  const isOutOfStock = quantity === 0;
  const finalPrice = isPromotion ? discountedPrice : price;

  return (
    &lt;div className={`product-card ${isOutOfStock ? 'out-of-stock' : 'in-stock'}`}&gt;
      &lt;h3&gt;{name}&lt;/h3&gt;

      {isPromotion && (
        &lt;div className="promotion-badge"&gt;
          🔥 Promotion ! Économisez {price - discountedPrice} FCFA
        &lt;/div&gt;
      )}

      &lt;div className="price"&gt;
        {isPromotion ? (
          &lt;&gt;
            &lt;span className="old-price"&gt;{price.toLocaleString()} FCFA&lt;/span&gt;
            &lt;span className="new-price"&gt;{finalPrice.toLocaleString()} FCFA&lt;/span&gt;
          &lt;/&gt;
        ) : (
          &lt;span className="price"&gt;{price.toLocaleString()} FCFA&lt;/span&gt;
        )}
      &lt;/div&gt;

      &lt;div className="stock-status"&gt;
        {isOutOfStock ? (
          &lt;span className="out"&gt;⛔ Rupture de stock&lt;/span&gt;
        ) : (
          &lt;span className="in"&gt;✅ En stock ({quantity} unités)&lt;/span&gt;
        )}
      &lt;/div&gt;

      &lt;button disabled={isOutOfStock}&gt;
        {isOutOfStock ? 'Indisponible' : 'Ajouter au panier'}
      &lt;/button&gt;
    &lt;/div&gt;
  );
}
```
